<script setup lang="ts">
import {computed,onMounted,ref} from 'vue';import {Activity,AlertTriangle,CheckCircle2,FileClock,Plus,Settings,Star} from 'lucide-vue-next';import KpiCard from '../components/common/KpiCard.vue';import StatusBadge from '../components/common/StatusBadge.vue';import {api} from '../api/client'
